from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler
import os
import datetime

app = Flask(__name__)

LOG_FILE = os.environ.get("AUTH_LOG_FILE", "application.log")

logger = logging.getLogger("auth_logger")
logger.setLevel(logging.INFO)

if not logger.handlers:
    handler = RotatingFileHandler(LOG_FILE, maxBytes=10 * 1024 * 1024, backupCount=5, encoding="utf-8")
    formatter = logging.Formatter(
        fmt="%(asctime)s %(levelname)s %(message)s",
        datefmt="%Y-%m-%dT%H:%M:%S%z",
    )
    handler.setFormatter(formatter)
    logger.addHandler(handler)
    logger.propagate = False


def get_client_ip(req):
    xff = req.headers.get("X-Forwarded-For", "")
    if xff:
        return xff.split(",")[0].strip()
    return req.remote_addr or ""


def log_attempt(username, password, email, success, reason=""):
    ip = get_client_ip(request)
    ua = request.headers.get("User-Agent", "")
    logger.info(
        'login_attempt success=%s reason="%s" username="%s" password="%s" email="%s" ip="%s" user_agent="%s"',
        str(bool(success)).lower(),
        (reason or "").replace('"', '\\"'),
        (username or "").replace('"', '\\"'),
        (password or "").replace('"', '\\"'),
        (email or "").replace('"', '\\"'),
        (ip or "").replace('"', '\\"'),
        (ua or "").replace('"', '\\"'),
    )


USERS = {
    "admin": {"password": "password123", "email": "admin@example.com"},
    "user": {"password": "secret", "email": "user@example.com"},
}


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok", "time": datetime.datetime.utcnow().isoformat() + "Z"}), 200


@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or {}
    username = data.get("username", "")
    password = data.get("password", "")
    email = data.get("email", "")

    user = USERS.get(username)
    if not user:
        log_attempt(username, password, email, success=False, reason="unknown_user")
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    if email and (user.get("email") != email):
        log_attempt(username, password, email, success=False, reason="email_mismatch")
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    if user.get("password") != password:
        log_attempt(username, password, email, success=False, reason="bad_password")
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    log_attempt(username, password, email, success=True, reason="authenticated")
    return jsonify({"ok": True, "message": "logged_in"}), 200


@app.route("/logout", methods=["POST"])
def logout():
    return jsonify({"ok": True, "message": "logged_out"}), 200


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", "5000")))